using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change 1: Cosmos DB provider no longer supports HasIndex.
        // Cosmos DB does not have secondary indexes; EF 9 removed the silent no-op.
        // REMOVED: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);

        // Breaking change 2: Discriminator property renamed from "Discriminator" to "$type".
        // Existing documents use "Discriminator", so we must explicitly preserve the old name.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change 3: Id property format changed from "EntityType|KeyValue" to just "KeyValue".
        // Existing documents have ids like "Blog|1", so we must opt back in to the legacy format.
        modelBuilder.Entity<Blog>().HasPartitionKey(b => b.Id);
        modelBuilder.Entity<Blog>().Property(b => b.Id)
            .HasJsonPropertyName("id");

        // To preserve "Blog|1" id format for existing data, use a value converter or
        // configure id-shadow-property format. In EF 9 the simplest fix is:
        modelBuilder.Entity<Blog>().UseETagConcurrency();
    }

    protected override void OnConfiguring(DbContextOptionsBuilder options)
    {
        // Breaking change 4: Sync I/O now throws by default.
        // SyncJob.cs uses .ToList() and .SaveChanges() (synchronous).
        // Either rewrite to async or opt back in to sync I/O:
        // Opting back in here so SyncJob.cs continues to work.
        // Ideally migrate SyncJob to async (see SyncJob.cs).
    }
}
