using Microsoft.EntityFrameworkCore;

class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // BREAKING CHANGE 1 – HasIndex now throws (Cosmos has no secondary indexes).
        // EF 8 silently ignored it; EF 9 raises InvalidOperationException.
        // FIX: Remove the call entirely.
        // REMOVED: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);

        // BREAKING CHANGE 2 – Discriminator property renamed "$type" (was "Discriminator").
        // Existing documents store "Discriminator"; keep the old name so queries still match.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // BREAKING CHANGE 3 – id value is now just the key (was "EntityType|Key").
        // Existing documents have id = "Blog|1". Use a value converter to preserve format.
        modelBuilder.Entity<Blog>().Property(b => b.Id)
            .HasConversion(
                v => "Blog|" + v,
                v => v.StartsWith("Blog|") ? v.Substring(5) : v);
    }
}

class Blog { public string Id { get; set; } public string Name { get; set; } }

