using Microsoft.EntityFrameworkCore;

// BREAKING CHANGE 4 – Synchronous I/O on the Cosmos provider now throws
// InvalidOperationException by default in EF 9.
// FIX: Convert to async (preferred) or call
//      options.UseCosmos(..., o => o.AllowSynchronousQueryExecution(true))
class SyncJob
{
    async Task RunAsync(BlogContext context)
    {
        var blogs = await context.Blogs.ToListAsync();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        await context.SaveChangesAsync();
    }
}

